export const categories = ['All', 'Main', 'Soup', 'Salad', 'Dessert', 'Bakery'];
export const difficulties = ['Easy', 'Medium', 'Advanced'];

export function searchRecipes(query) {
  const lower = query.toLowerCase();
  return recipes.filter(r =>
    r.name.toLowerCase().includes(lower) ||
    r.ingredients.some(i => i.toLowerCase().includes(lower)) ||
    r.category.toLowerCase().includes(lower) ||
    r.difficulty.toLowerCase().includes(lower)
  );
}

export function filterByCategory(category) {
  if (category.toLowerCase() === 'all') return recipes;
  return recipes.filter(r => r.category.toLowerCase() === category.toLowerCase());
}

export function filterByDifficulty(difficulty) {
  return recipes.filter(r => r.difficulty.toLowerCase() === difficulty.toLowerCase());
}

export function getFavorites() {
  try { return JSON.parse(localStorage.getItem('cheffear_favIds') || '[]'); } catch { return []; }
}

export function toggleFavorite(recipeId) {
  const favorites = getFavorites();
  const idx = favorites.indexOf(recipeId);
  if (idx > -1) favorites.splice(idx, 1);
  else favorites.push(recipeId);
  localStorage.setItem('cheffear_favIds', JSON.stringify(favorites));
  return favorites;
}

export function isFavorite(recipeId) {
  return getFavorites().includes(recipeId);
}

export function getHistory() {
  try { return JSON.parse(localStorage.getItem('cheffear_history') || '[]'); } catch { return []; }
}

export function saveCookingSession(recipeId, completed, durationMinutes) {
  const history = getHistory();
  history.unshift({ recipeId, completed, duration: durationMinutes, date: new Date().toISOString() });
  localStorage.setItem('cheffear_history', JSON.stringify(history.slice(0, 50)));
}

export function getRecipeById(id) {
  return recipes.find(r => r.id === id);
}

export function getRecentRecipes(limit = 5) {
  const history = getHistory();
  const recentIds = [...new Set(history.map(h => h.recipeId))].slice(0, limit);
  return recentIds.map(id => getRecipeById(id)).filter(Boolean);
}

export function getFavoriteRecipes() {
  const favIds = getFavorites();
  return favIds.map(id => getRecipeById(id)).filter(Boolean);
}

export function trackEvent(event, data = {}) {
  try {
    const events = JSON.parse(localStorage.getItem('cheffear_events') || '[]');
    events.push({ event, data, timestamp: Date.now() });
    localStorage.setItem('cheffear_events', JSON.stringify(events.slice(-100)));
  } catch {}
}